mapper.select:
SELECT count(*)
FROM dm_auth_res
WHERE owner_uid = #{ownerUid}

SELECT
FROM dm_auth_res WHERE owner_uid = #{ownerUid} and res_id = #{resId} and kind_type = #{authKind,javaType=com.clougence.clouddm.sdk.security.auth.AuthKind}
#{item} like concat(res_path,'%')

mapper.update:
UPDATE
dm_auth_res
SET
res_auth_label = #{resAuthLabel}
, start_time=#{startTime}
, end_time=#{endTime}
WHERE
id = #{id}

mapper.delete:
DELETE
FROM dm_auth_res
WHERE res_id = #{resId}
  and kind_type = #{authKind,javaType=com.clougence.clouddm.sdk.security.auth.AuthKind}

DELETE
FROM dm_auth_res
WHERE owner_uid = #{ownerUid}
  and kind_type = #{authKind,javaType=com.clougence.clouddm.sdk.security.auth.AuthKind}
  and res_id = 0
  and res_path = '/'
